{
  "summary": "This paper proposes vote-k, an unsupervised graph-based selective annotation method designed to improve annotation efficiency for in-context learning (ICL) with large language models. By jointly optimizing diversity and representativeness in selecting examples to annotate, vote-k significantly enhances ICL performance and stability across diverse NLP tasks while reducing annotation costs compared to random selection and supervised finetuning.",
  "strengths": [
    {
      "point": "Novel unsupervised selective annotation method tailored for ICL",
      "evidence": "vote-k constructs a directed k-NN graph and iteratively selects examples balancing representativeness and diversity, improving ICL performance."
    },
    {
      "point": "Extensive empirical validation across 10 diverse NLP datasets and multiple LLM sizes",
      "evidence": "Experiments show 11.4% average relative gain at 100 examples and 12.9% at 18 examples, with robustness under domain shifts and variance reduction."
    },
    {
      "point": "Demonstrated annotation cost reduction compared to supervised finetuning",
      "evidence": "ICL with vote-k matches or outperforms finetuning with 10-100× less annotation cost."
    },
    {
      "point": "Insightful analysis of the synergy between selective annotation and similarity-based prompt retrieval",
      "evidence": "Selective annotation benefits ICL only when combined with similarity-based retrieval, highlighting the importance of retrieval strategy."
    }
  ],
  "weaknesses": [
    {
      "point": "Lack of comparison to strong classical and recent selective sampling baselines",
      "evidence": "No experimental or detailed discussion comparing vote-k to methods like BADGE, CoreSet, or uncertainty-diversity hybrids."
    },
    {
      "point": "Insufficient ablation studies on key design choices",
      "evidence": "No empirical analysis of the choice of k in k-NN graph, impact of confidence bucketing, or diversity-representativeness tradeoff across annotation budgets."
    },
    {
      "point": "Missing statistical significance testing and confidence intervals",
      "evidence": "Reported performance gains lack formal statistical validation, undermining confidence in robustness."
    },
    {
      "point": "Reproducibility concerns due to missing embedding and algorithmic details",
      "evidence": "Critical details about Sentence-BERT variant, embedding computation, vote-k scoring function, hyperparameters, and pseudocode are omitted."
    },
    {
      "point": "Limited evaluation of retrieval baselines and annotation cost fairness",
      "evidence": "Only random prompt retrieval baseline evaluated; finetuning baseline details insufficient to assess fairness."
    },
    {
      "point": "Scalability and generalizability not thoroughly analyzed",
      "evidence": "No detailed runtime or memory analysis for large unlabeled pools; no evaluation on other modalities or embedding model sensitivity."
    },
    {
      "point": "Clarity issues in formalizing key concepts and terminology",
      "evidence": "Terms like representativeness, diversity, and confidence buckets are undefined or inconsistently used."
    }
  ],
  "questions": [
    {
      "question": "How does vote-k compare empirically to established active learning and core-set selection methods?",
      "motivation": "Understanding relative performance against strong baselines is essential to assess novelty and practical advantage."
    },
    {
      "question": "What is the sensitivity of vote-k to the choice of k in the k-NN graph and to the embedding model used?",
      "motivation": "These factors critically affect selection quality and robustness, impacting applicability across datasets and domains."
    },
    {
      "question": "Can vote-k support interactive or incremental annotation workflows common in practice?",
      "motivation": "Practical deployment often requires human-in-the-loop or adaptive annotation strategies beyond fixed batch selection."
    },
    {
      "question": "How robust is vote-k to label noise and annotation errors in real-world settings?",
      "motivation": "Annotation imperfections are common and can affect selection quality and downstream ICL performance."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
